// Sensible defaults: skip the worst-rated, skip FSK 18, full year + runtime range
const DEFAULT_PREFS = {
  selectedGenres: [],
  yearMin: YEAR_MIN_BOUND,
  yearMax: YEAR_MAX_BOUND,
  runtimeMin: RUNTIME_MIN_BOUND,
  runtimeMax: RUNTIME_MAX_BOUND,
  fskMin: 0,
  fskMax: 16,
  ratingMin: 6.0,
  ratingMax: 10.0,
};

const FSK_VALUES = [0, 6, 12, 16, 18];

function Fireworks() {
  // Generate sparkle particles with random angles, distances, colors, and delays
  const particles = useMemo(() => {
    const colors = ['#fbbf24', '#f472b6', '#a78bfa', '#22d3ee', '#fb7185', '#34d399', '#fde047'];
    const out = [];
    // Three bursts at different positions
    const bursts = [
      { x: 50, y: 35 },
      { x: 25, y: 55 },
      { x: 75, y: 50 },
    ];
    bursts.forEach((burst, bi) => {
      const count = 22;
      for (let i = 0; i < count; i++) {
        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.3;
        const distance = 80 + Math.random() * 140;
        out.push({
          id: `${bi}-${i}`,
          x: burst.x,
          y: burst.y,
          dx: Math.cos(angle) * distance,
          dy: Math.sin(angle) * distance,
          color: colors[Math.floor(Math.random() * colors.length)],
          size: 2 + Math.random() * 4,
          delay: bi * 0.15 + Math.random() * 0.1,
          duration: 0.9 + Math.random() * 0.5,
        });
      }
    });
    return out;
  }, []);

  return (
    <div className="pointer-events-none fixed inset-0 z-50 overflow-hidden">
      <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
        {particles.map(p => (
          <circle
            key={p.id}
            cx={p.x}
            cy={p.y}
            r={p.size / 10}
            fill={p.color}
            style={{
              animation: `firework ${p.duration}s ease-out ${p.delay}s forwards`,
              transformOrigin: `${p.x}px ${p.y}px`,
              '--dx': `${p.dx / 10}px`,
              '--dy': `${p.dy / 10}px`,
            }}
          />
        ))}
      </svg>
      {/* Big star bursts as text emojis for that extra pop */}
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="relative w-full h-full">
          {['✨', '⭐', '✨'].map((emoji, i) => (
            <div
              key={i}
              className="absolute text-4xl"
              style={{
                left: `${20 + i * 30}%`,
                top: `${30 + (i % 2) * 15}%`,
                animation: `starPop 0.8s ease-out ${i * 0.1}s both`,
              }}
            >
              {emoji}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function MiniHistogram({ data, min, max, valueMin, valueMax, bucketCount = 30, accent = '#fbbf24' }) {
  const { buckets, maxCount } = useMemo(() => {
    const bucketSize = (max - min) / bucketCount;
    const counts = new Array(bucketCount).fill(0);
    data.forEach(v => {
      if (v == null || v < min || v > max) return;
      const idx = Math.min(bucketCount - 1, Math.floor((v - min) / bucketSize));
      counts[idx]++;
    });
    return { buckets: counts, maxCount: Math.max(1, ...counts) };
  }, [data, min, max, bucketCount]);

  const range = max - min;

  return (
    <div className="flex items-end gap-[1px] h-7 w-full">
      {buckets.map((c, i) => {
        const bucketStart = min + (range * i) / bucketCount;
        const bucketEnd = min + (range * (i + 1)) / bucketCount;
        const active = bucketEnd > valueMin && bucketStart < valueMax;
        const height = (c / maxCount) * 100;
        return (
          <div
            key={i}
            className="flex-1 rounded-t-[1px]"
            style={{
              height: `${Math.max(8, height)}%`,
              background: active ? accent : 'rgba(82,82,91,0.4)',
            }}
          />
        );
      })}
    </div>
  );
}

function HistogramRange({ data, min, max, valueMin, valueMax, onChangeMin, onChangeMax, bucketCount = 24, formatValue, step = 1, accent = '#fbbf24' }) {
  const { buckets, maxCount } = useMemo(() => {
    const bucketSize = (max - min) / bucketCount;
    const counts = new Array(bucketCount).fill(0);
    data.forEach(v => {
      if (v == null || v < min || v > max) return;
      const idx = Math.min(bucketCount - 1, Math.floor((v - min) / bucketSize));
      counts[idx]++;
    });
    return { buckets: counts, maxCount: Math.max(1, ...counts) };
  }, [data, min, max, bucketCount]);

  const range = max - min;
  const minPct = ((valueMin - min) / range) * 100;
  const maxPct = ((valueMax - min) / range) * 100;

  return (
    <div className="select-none">
      {/* Histogram bars */}
      <div className="flex items-end gap-[2px] h-14 mb-1.5 px-[10px]">
        {buckets.map((c, i) => {
          const bucketStart = min + (range * i) / bucketCount;
          const bucketEnd = min + (range * (i + 1)) / bucketCount;
          // Active if any part of the bucket falls in [valueMin, valueMax]
          const active = bucketEnd > valueMin && bucketStart < valueMax;
          const height = (c / maxCount) * 100;
          return (
            <div
              key={i}
              className="flex-1 rounded-t-sm transition-colors duration-150"
              style={{
                height: `${Math.max(3, height)}%`,
                background: active ? accent : 'rgba(82,82,91,0.55)',
                opacity: active ? 0.85 : 1,
              }}
            />
          );
        })}
      </div>

      {/* Dual range slider */}
      <div className="dual-range relative h-9 px-[10px]">
        {/* Track */}
        <div className="absolute top-1/2 left-[10px] right-[10px] h-1 -translate-y-1/2 rounded-full bg-zinc-700/60" />
        {/* Active range */}
        <div
          className="absolute top-1/2 h-1 -translate-y-1/2 rounded-full"
          style={{
            left: `calc(10px + ${minPct}% - ${minPct * 0.2}px)`,
            right: `calc(10px + ${100 - maxPct}% - ${(100 - maxPct) * 0.2}px)`,
            background: accent,
          }}
        />
        <input
          type="range" min={min} max={max} step={step} value={valueMin}
          onChange={e => onChangeMin(Math.min(valueMax - step, parseFloat(e.target.value)))}
          className="dual-range-input"
          style={{ zIndex: valueMin > max - range * 0.1 ? 3 : 2 }}
        />
        <input
          type="range" min={min} max={max} step={step} value={valueMax}
          onChange={e => onChangeMax(Math.max(valueMin + step, parseFloat(e.target.value)))}
          className="dual-range-input"
          style={{ zIndex: 3 }}
        />
      </div>

      {/* Labels */}
      <div className="flex justify-between text-xs text-zinc-300 mt-1 px-1 font-mono">
        <span>{formatValue ? formatValue(valueMin) : valueMin}</span>
        <span>{formatValue ? formatValue(valueMax) : valueMax}</span>
      </div>
    </div>
  );
}

export default function FilmWuerfel() {
  const [showFilters, setShowFilters] = useState(false);
  const [selectedGenres, setSelectedGenres] = useState(DEFAULT_PREFS.selectedGenres);
  const [yearMin, setYearMin] = useState(DEFAULT_PREFS.yearMin);
  const [yearMax, setYearMax] = useState(DEFAULT_PREFS.yearMax);
  const [runtimeMin, setRuntimeMin] = useState(DEFAULT_PREFS.runtimeMin);
  const [runtimeMax, setRuntimeMax] = useState(DEFAULT_PREFS.runtimeMax);
  const [fskMin, setFskMin] = useState(DEFAULT_PREFS.fskMin);
  const [fskMax, setFskMax] = useState(DEFAULT_PREFS.fskMax);
  const [ratingMin, setRatingMin] = useState(DEFAULT_PREFS.ratingMin);
  const [ratingMax, setRatingMax] = useState(DEFAULT_PREFS.ratingMax);
  const [picked, setPicked] = useState(null);
  const [rolling, setRolling] = useState(false);
  const [ticker, setTicker] = useState(null);
  const [fireworks, setFireworks] = useState(false);
  const [fireworksKey, setFireworksKey] = useState(0);
  const [history, setHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);
  const [prefsLoaded, setPrefsLoaded] = useState(false);

  // Load saved preferences on mount
  useEffect(() => {
    (async () => {
      try {
        if (window.storage && window.storage.get) {
          const saved = await window.storage.get(PREFS_KEY);
          if (saved && saved.value) {
            const p = typeof saved.value === 'string' ? JSON.parse(saved.value) : saved.value;
            if (Array.isArray(p.selectedGenres)) setSelectedGenres(p.selectedGenres);
            if (typeof p.yearMin === 'number') setYearMin(p.yearMin);
            if (typeof p.yearMax === 'number') setYearMax(p.yearMax);
            if (typeof p.runtimeMin === 'number') setRuntimeMin(p.runtimeMin);
            if (typeof p.runtimeMax === 'number') setRuntimeMax(p.runtimeMax);
            // Migrate old single-sided prefs to dual-sided
            if (typeof p.fskMin === 'number') setFskMin(p.fskMin);
            if (typeof p.fskMax === 'number') setFskMax(p.fskMax);
            else if (typeof p.maxFsk === 'number') setFskMax(p.maxFsk);
            if (typeof p.ratingMin === 'number') setRatingMin(p.ratingMin);
            else if (typeof p.minRating === 'number') setRatingMin(p.minRating);
            if (typeof p.ratingMax === 'number') setRatingMax(p.ratingMax);
          }
        }
      } catch (e) { /* ignore */ }
      setPrefsLoaded(true);
    })();
  }, []);

  // Persist preferences whenever they change (after initial load)
  useEffect(() => {
    if (!prefsLoaded) return;
    (async () => {
      try {
        if (window.storage && window.storage.set) {
          await window.storage.set(PREFS_KEY, JSON.stringify({
            selectedGenres, yearMin, yearMax, runtimeMin, runtimeMax, fskMin, fskMax, ratingMin, ratingMax
          }));
        }
      } catch (e) { /* ignore */ }
    })();
  }, [prefsLoaded, selectedGenres, yearMin, yearMax, runtimeMin, runtimeMax, fskMin, fskMax, ratingMin, ratingMax]);

  const filtered = useMemo(() => {
    return MOVIES.filter(m => {
      if (selectedGenres.length > 0 && !selectedGenres.every(g => m.g.includes(g))) return false;
      if (m.y && (m.y < yearMin || m.y > yearMax)) return false;
      if (m.r && (m.r < runtimeMin || m.r > runtimeMax)) return false;
      if (m.f !== null && m.f !== undefined && (m.f < fskMin || m.f > fskMax)) return false;
      if (m.s !== null && m.s !== undefined && (m.s < ratingMin || m.s > ratingMax)) return false;
      return true;
    });
  }, [selectedGenres, yearMin, yearMax, runtimeMin, runtimeMax, fskMin, fskMax, ratingMin, ratingMax]);

  const pick = () => {
    if (filtered.length === 0) return;
    setRolling(true);
    setShowFilters(false);
    setShowHistory(false);

    // Pre-select winner so it's stable from the start
    const choice = filtered[Math.floor(Math.random() * filtered.length)];

    // Cycle through random titles as a "slot machine" ticker
    const tickInterval = setInterval(() => {
      const random = filtered[Math.floor(Math.random() * filtered.length)];
      setTicker(random);
    }, 90);

    // After ~2.4s reveal the winner with fireworks
    setTimeout(() => {
      clearInterval(tickInterval);
      setTicker(null);
      setPicked(choice);
      setHistory(h => [choice, ...h.filter(x => x.t !== choice.t || x.y !== choice.y)].slice(0, 12));
      setRolling(false);
      // Trigger fireworks burst
      setFireworksKey(k => k + 1);
      setFireworks(true);
      setTimeout(() => setFireworks(false), 1800);
    }, 2400);
  };


  const toggleGenre = (g) => {
    setSelectedGenres(prev => prev.includes(g) ? prev.filter(x => x !== g) : [...prev, g]);
  };

  const resetFilters = () => {
    setSelectedGenres(DEFAULT_PREFS.selectedGenres);
    setYearMin(DEFAULT_PREFS.yearMin);
    setYearMax(DEFAULT_PREFS.yearMax);
    setRuntimeMin(DEFAULT_PREFS.runtimeMin);
    setRuntimeMax(DEFAULT_PREFS.runtimeMax);
    setFskMin(DEFAULT_PREFS.fskMin);
    setFskMax(DEFAULT_PREFS.fskMax);
    setRatingMin(DEFAULT_PREFS.ratingMin);
    setRatingMax(DEFAULT_PREFS.ratingMax);
  };

  const activeFilterCount = (selectedGenres.length > 0 ? 1 : 0)
    + (yearMin !== YEAR_MIN_BOUND || yearMax !== YEAR_MAX_BOUND ? 1 : 0)
    + (runtimeMin !== RUNTIME_MIN_BOUND || runtimeMax !== RUNTIME_MAX_BOUND ? 1 : 0)
    + (fskMin > 0 || fskMax < 18 ? 1 : 0)
    + (ratingMin > 0 || ratingMax < 10 ? 1 : 0);

  return (
    <>
      <style>{`
        @keyframes danceBg {
          0% { background-position: 0% 50%; opacity: 0.55; }
          25% { background-position: 50% 100%; opacity: 0.85; }
          50% { background-position: 100% 50%; opacity: 0.7; }
          75% { background-position: 50% 0%; opacity: 0.95; }
          100% { background-position: 0% 50%; opacity: 0.55; }
        }
        @keyframes glowPulse {
          0%, 100% {
            box-shadow: 0 0 24px 2px rgba(251,191,36,0.45), 0 0 60px 6px rgba(251,191,36,0.18);
          }
          50% {
            box-shadow: 0 0 36px 6px rgba(251,191,36,0.75), 0 0 100px 18px rgba(244,114,182,0.35), 0 0 140px 30px rgba(124,58,237,0.18);
          }
        }
        @keyframes diceShake {
          0%, 100% { transform: rotate(0deg); }
          20% { transform: rotate(-18deg) translateY(-1px); }
          40% { transform: rotate(14deg) translateY(1px); }
          60% { transform: rotate(-12deg); }
          80% { transform: rotate(18deg); }
        }
        @keyframes tickerPop {
          0% { transform: scale(0.97); opacity: 0.5; }
          50% { opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        @keyframes firework {
          0% {
            transform: translate(0, 0) scale(0);
            opacity: 1;
          }
          15% {
            transform: translate(0, 0) scale(1.4);
            opacity: 1;
          }
          100% {
            transform: translate(var(--dx), var(--dy)) scale(0);
            opacity: 0;
          }
        }
        @keyframes starPop {
          0% { transform: scale(0) rotate(0deg); opacity: 0; }
          30% { transform: scale(1.6) rotate(180deg); opacity: 1; }
          60% { transform: scale(1.1) rotate(280deg); opacity: 0.9; }
          100% { transform: scale(2.4) rotate(360deg); opacity: 0; }
        }
        @keyframes revealCard {
          0% { transform: scale(0.92); opacity: 0; filter: blur(8px); }
          60% { transform: scale(1.02); opacity: 1; filter: blur(0); }
          100% { transform: scale(1); opacity: 1; filter: blur(0); }
        }
        .reveal-card {
          animation: revealCard 0.55s cubic-bezier(0.34, 1.56, 0.64, 1) both;
        }
        .rolling-bg {
          background: linear-gradient(125deg,
            rgba(251,191,36,0.22) 0%,
            rgba(244,114,182,0.18) 25%,
            rgba(124,58,237,0.16) 50%,
            rgba(34,211,238,0.14) 75%,
            rgba(251,191,36,0.22) 100%);
          background-size: 400% 400%;
          animation: danceBg 2.4s ease-in-out infinite;
          filter: blur(2px);
        }
        .glow-pulse {
          animation: glowPulse 0.9s ease-in-out infinite;
        }
        .dice-shake {
          display: inline-block;
          animation: diceShake 0.4s ease-in-out infinite;
        }
        .ticker-pop {
          animation: tickerPop 0.12s ease-out;
        }
        /* Dual range slider */
        .dual-range-input {
          position: absolute;
          top: 0;
          left: 10px;
          right: 10px;
          width: calc(100% - 20px);
          height: 36px;
          background: transparent;
          -webkit-appearance: none;
          appearance: none;
          pointer-events: none;
          outline: none;
          margin: 0;
        }
        .dual-range-input::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          pointer-events: auto;
          width: 22px;
          height: 22px;
          border-radius: 50%;
          background: #fbbf24;
          border: 3px solid #18181b;
          box-shadow: 0 2px 8px rgba(0,0,0,0.5);
          cursor: pointer;
        }
        .dual-range-input::-moz-range-thumb {
          pointer-events: auto;
          width: 22px;
          height: 22px;
          border-radius: 50%;
          background: #fbbf24;
          border: 3px solid #18181b;
          box-shadow: 0 2px 8px rgba(0,0,0,0.5);
          cursor: pointer;
        }
        .dual-range-input::-webkit-slider-runnable-track {
          background: transparent;
          height: 36px;
        }
        .dual-range-input::-moz-range-track {
          background: transparent;
          height: 36px;
        }
      `}</style>
      <div className="min-h-screen bg-zinc-950 text-zinc-100 relative overflow-hidden" style={{ fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif' }}>
        {/* Ambient atmospheric gradient (always visible, subtle) */}
        <div className="fixed inset-0 pointer-events-none" style={{
          background: 'radial-gradient(ellipse 80% 50% at 50% 0%, rgba(251, 191, 36, 0.08), transparent 70%), radial-gradient(ellipse 60% 40% at 50% 100%, rgba(124, 58, 237, 0.06), transparent 70%)'
        }} />

        {/* Rolling dance overlay (only during roll) */}
        {rolling && (
          <div className="fixed inset-0 pointer-events-none rolling-bg" />
        )}

        {/* Fireworks on reveal */}
        {fireworks && <Fireworks key={fireworksKey} />}

        <div className="relative max-w-2xl mx-auto px-4 py-6 sm:py-10">
        {/* Header */}
        <header className="mb-6">
          <div className="flex items-center gap-3 mb-1">
            <div className="w-10 h-10 rounded-2xl bg-amber-400 flex items-center justify-center shadow-lg shadow-amber-400/20">
              <Film className="w-5 h-5 text-zinc-950" strokeWidth={2.5} />
            </div>
            <div className="min-w-0 flex-1">
              <h1 className="text-2xl font-bold tracking-tight" style={{ fontFamily: 'Georgia, "Times New Roman", serif' }}>Filmwürfel</h1>
              <p className="text-sm">
                <span className={activeFilterCount > 0 ? 'text-amber-400 font-bold' : 'text-zinc-200 font-medium'}>{filtered.length.toLocaleString('de-DE')}</span>
                <span className="text-zinc-400"> von {MOVIES.length.toLocaleString('de-DE')} Filmen{activeFilterCount > 0 ? ' (gefiltert)' : ''}</span>
              </p>
            </div>
          </div>
        </header>

        {/* Filter toggle bar */}
        <div className="flex gap-2 mb-4">
          <button
            onClick={() => setShowFilters(s => !s)}
            className="flex-1 flex items-center justify-between gap-2 px-4 py-3 rounded-2xl bg-zinc-900 border border-zinc-800 active:scale-[0.98] transition-transform"
          >
            <span className="flex items-center gap-2">
              <SlidersHorizontal className="w-4 h-4 text-zinc-400" />
              <span className="font-medium">Filter</span>
              {activeFilterCount > 0 && (
                <span className="px-2 py-0.5 rounded-full bg-amber-400 text-zinc-950 text-xs font-bold">{activeFilterCount}</span>
              )}
            </span>
            {showFilters ? <ChevronUp className="w-4 h-4 text-zinc-400" /> : <ChevronDown className="w-4 h-4 text-zinc-400" />}
          </button>
          {history.length > 0 && (
            <button
              onClick={() => setShowHistory(s => !s)}
              className="px-4 py-3 rounded-2xl bg-zinc-900 border border-zinc-800 active:scale-[0.98] transition-transform"
              aria-label="Verlauf"
            >
              <HistoryIcon className="w-4 h-4 text-zinc-400" />
            </button>
          )}
        </div>

        {/* Mini histogram preview when filters are collapsed - always shows where ranges sit */}
        {!showFilters && (
          <button
            onClick={() => setShowFilters(true)}
            className="w-full mb-4 p-3 rounded-2xl bg-zinc-900/60 border border-zinc-800 active:scale-[0.99] transition-transform"
          >
            <div className="grid grid-cols-2 gap-3">
              <div>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-[10px] uppercase tracking-wider text-zinc-500 flex items-center gap-1">
                    <Calendar className="w-3 h-3" /> Jahr
                  </span>
                  <span className="text-[11px] text-amber-400 font-mono">{yearMin}–{yearMax}</span>
                </div>
                <MiniHistogram
                  data={MOVIES.map(m => m.y).filter(Boolean)}
                  min={YEAR_MIN_BOUND} max={YEAR_MAX_BOUND}
                  valueMin={yearMin} valueMax={yearMax}
                  bucketCount={32}
                />
              </div>
              <div>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-[10px] uppercase tracking-wider text-zinc-500 flex items-center gap-1">
                    <Clock className="w-3 h-3" /> Spielzeit
                  </span>
                  <span className="text-[11px] text-amber-400 font-mono">{formatRuntime(runtimeMin)}–{formatRuntime(runtimeMax)}</span>
                </div>
                <MiniHistogram
                  data={MOVIES.map(m => m.r).filter(Boolean)}
                  min={RUNTIME_MIN_BOUND} max={RUNTIME_MAX_BOUND}
                  valueMin={runtimeMin} valueMax={runtimeMax}
                  bucketCount={28}
                />
              </div>
            </div>
          </button>
        )}

        {/* Filter panel */}
        {showFilters && (
          <div className="mb-4 p-4 rounded-2xl bg-zinc-900/60 border border-zinc-800 space-y-5">
            {/* Genres */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-sm font-medium text-zinc-300 flex items-center gap-2">
                  <Tag className="w-3.5 h-3.5" /> Genres
                </label>
                {selectedGenres.length > 0 && (
                  <button onClick={() => setSelectedGenres([])} className="text-xs text-amber-400/80 active:text-amber-300 font-medium">leeren</button>
                )}
              </div>
              <div className="flex flex-wrap gap-2">
                {ALL_GENRES.map(g => {
                  const on = selectedGenres.includes(g);
                  return (
                    <button
                      key={g}
                      onClick={() => toggleGenre(g)}
                      className={`px-3 py-1.5 rounded-xl text-sm border transition-colors active:scale-95 ${on
                        ? 'bg-amber-400 text-zinc-950 border-amber-400 font-medium'
                        : 'bg-zinc-900 text-zinc-300 border-zinc-800'}`}
                    >
                      {g}
                    </button>
                  );
                })}
              </div>
              {selectedGenres.length > 0 && (
                <p className="text-xs text-zinc-400 mt-2">Treffer wenn alle gewählten Genres passen</p>
              )}
            </div>

            {/* Year range with histogram */}
            <div>
              <label className="text-sm font-medium text-zinc-200 flex items-center gap-2 mb-2">
                <Calendar className="w-3.5 h-3.5" /> Jahr: <span className="text-amber-400 font-mono">{yearMin}</span> – <span className="text-amber-400 font-mono">{yearMax}</span>
              </label>
              <HistogramRange
                data={MOVIES.map(m => m.y).filter(Boolean)}
                min={YEAR_MIN_BOUND}
                max={YEAR_MAX_BOUND}
                valueMin={yearMin}
                valueMax={yearMax}
                onChangeMin={setYearMin}
                onChangeMax={setYearMax}
                bucketCount={31}
                step={1}
              />
            </div>

            {/* Runtime range with histogram */}
            <div>
              <label className="text-sm font-medium text-zinc-200 flex items-center gap-2 mb-2">
                <Clock className="w-3.5 h-3.5" /> Spielzeit: <span className="text-amber-400 font-mono">{formatRuntime(runtimeMin)}</span> – <span className="text-amber-400 font-mono">{formatRuntime(runtimeMax)}</span>
              </label>
              <HistogramRange
                data={MOVIES.map(m => m.r).filter(Boolean)}
                min={RUNTIME_MIN_BOUND}
                max={RUNTIME_MAX_BOUND}
                valueMin={runtimeMin}
                valueMax={runtimeMax}
                onChangeMin={setRuntimeMin}
                onChangeMax={setRuntimeMax}
                bucketCount={24}
                step={5}
                formatValue={formatRuntime}
              />
            </div>

            {/* FSK range with histogram (discrete) */}
            <div>
              <label className="text-sm font-medium text-zinc-200 flex items-center gap-2 mb-2">
                <ShieldAlert className="w-3.5 h-3.5" /> FSK: <span className="text-amber-400 font-mono">{fskMin}</span> – <span className="text-amber-400 font-mono">{fskMax}</span>
              </label>
              {(() => {
                const counts = FSK_VALUES.map(f => MOVIES.filter(m => m.f === f).length);
                const maxC = Math.max(1, ...counts);
                const minIdx = FSK_VALUES.indexOf(fskMin);
                const maxIdx = FSK_VALUES.indexOf(fskMax);
                return (
                  <div>
                    {/* Bars */}
                    <div className="flex items-end gap-1.5 h-14 mb-2 px-[10px]">
                      {FSK_VALUES.map((f, i) => {
                        const active = f >= fskMin && f <= fskMax;
                        const h = (counts[i] / maxC) * 100;
                        return (
                          <div key={f} className="flex-1 flex flex-col justify-end" style={{ height: '100%' }}>
                            <div
                              className="w-full rounded-t-md transition-colors"
                              style={{
                                height: `${Math.max(8, h)}%`,
                                background: active ? '#fbbf24' : 'rgba(82,82,91,0.5)',
                              }}
                            />
                          </div>
                        );
                      })}
                    </div>

                    {/* Dual range slider (snaps to FSK indices) */}
                    <div className="dual-range relative h-9 px-[10px] mb-2">
                      <div className="absolute top-1/2 left-[10px] right-[10px] h-1 -translate-y-1/2 rounded-full bg-zinc-700/60" />
                      <div
                        className="absolute top-1/2 h-1 -translate-y-1/2 rounded-full bg-amber-400"
                        style={{
                          left: `calc(10px + ${(minIdx / (FSK_VALUES.length - 1)) * 100}%)`,
                          right: `calc(10px + ${100 - (maxIdx / (FSK_VALUES.length - 1)) * 100}%)`,
                        }}
                      />
                      <input
                        type="range" min={0} max={FSK_VALUES.length - 1} step={1} value={minIdx}
                        onChange={e => {
                          const v = parseInt(e.target.value);
                          setFskMin(FSK_VALUES[Math.min(v, maxIdx)]);
                        }}
                        className="dual-range-input"
                        style={{ zIndex: 2 }}
                      />
                      <input
                        type="range" min={0} max={FSK_VALUES.length - 1} step={1} value={maxIdx}
                        onChange={e => {
                          const v = parseInt(e.target.value);
                          setFskMax(FSK_VALUES[Math.max(v, minIdx)]);
                        }}
                        className="dual-range-input"
                        style={{ zIndex: 3 }}
                      />
                    </div>

                    {/* Labels with counts */}
                    <div className="flex gap-1.5 px-1">
                      {FSK_VALUES.map((f, i) => (
                        <div key={f} className="flex-1 text-center">
                          <div className={`text-xs font-bold ${f >= fskMin && f <= fskMax ? 'text-amber-400' : 'text-zinc-500'}`}>{f}</div>
                          <div className="text-[9px] text-zinc-500">{counts[i]}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })()}
            </div>

            {/* Rating range with histogram */}
            <div>
              <label className="text-sm font-medium text-zinc-200 flex items-center gap-2 mb-2">
                <Star className="w-3.5 h-3.5" /> Bewertung: <span className="text-amber-400 font-mono">{ratingMin.toFixed(1)}</span> – <span className="text-amber-400 font-mono">{ratingMax.toFixed(1)}</span>
              </label>
              <HistogramRange
                data={MOVIES.map(m => m.s).filter(s => s != null)}
                min={0}
                max={10}
                valueMin={ratingMin}
                valueMax={ratingMax}
                onChangeMin={setRatingMin}
                onChangeMax={setRatingMax}
                bucketCount={20}
                step={0.1}
                formatValue={v => v.toFixed(1)}
              />
            </div>

            <button onClick={resetFilters}
              className="w-full py-2 rounded-xl bg-zinc-800/60 text-zinc-300 text-sm font-medium border border-zinc-800 active:scale-[0.98] transition-transform flex items-center justify-center gap-2">
              <X className="w-3.5 h-3.5" /> Filter zurücksetzen
            </button>
          </div>
        )}

        {/* History panel */}
        {showHistory && history.length > 0 && (
          <div className="mb-4 p-4 rounded-2xl bg-zinc-900/60 border border-zinc-800">
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-sm font-medium text-zinc-300">Letzte Würfe</h3>
              <button onClick={() => setHistory([])} className="text-xs text-amber-400/80 active:text-amber-300 font-medium">leeren</button>
            </div>
            <div className="space-y-1.5">
              {history.map((m, i) => (
                <button key={i} onClick={() => { setPicked(m); setAiInfo(''); setShowHistory(false); }}
                  className="w-full text-left px-3 py-2 rounded-xl bg-zinc-950/60 border border-zinc-800/60 active:scale-[0.98] transition-transform">
                  <div className="text-sm font-medium text-zinc-200 truncate">{m.t}</div>
                  <div className="text-xs text-zinc-400">{m.y} · {m.g.slice(0, 2).join(', ')}</div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Roll button */}
        <button
          onClick={pick}
          disabled={filtered.length === 0 || rolling}
          className={`w-full py-5 rounded-2xl bg-amber-400 text-zinc-950 font-bold text-lg flex items-center justify-center gap-3 active:scale-[0.98] transition-transform disabled:opacity-40 disabled:active:scale-100 ${rolling ? 'glow-pulse' : 'shadow-xl shadow-amber-400/30'}`}
        >
          <span className={rolling ? 'dice-shake' : 'inline-block'}>
            <Dices className="w-6 h-6" strokeWidth={2.5} />
          </span>
          {rolling ? 'Würfle…' : picked ? 'Nochmal würfeln' : 'Film würfeln'}
        </button>

        {filtered.length === 0 && (
          <div className="mt-4 p-4 rounded-2xl bg-rose-500/10 border border-rose-500/20 flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-rose-400 shrink-0 mt-0.5" />
            <div className="text-sm text-rose-200">
              Keine Filme entsprechen deinen Filtern. Reduziere ein paar Kriterien.
            </div>
          </div>
        )}

        {/* Rolling ticker card (during roll only) */}
        {rolling && ticker && (
          <article className="mt-6 rounded-3xl bg-gradient-to-br from-amber-500/15 to-zinc-900/40 border border-amber-400/30 overflow-hidden">
            <div className="p-6 sm:p-8 text-center">
              <span className="text-xs uppercase tracking-widest text-amber-400 font-medium block mb-3">Würfle…</span>
              <h2 className="text-2xl sm:text-3xl font-bold leading-tight tracking-tight text-zinc-300 truncate" style={{ fontFamily: 'Georgia, "Times New Roman", serif' }}>
                {ticker.t}
              </h2>
              <p className="text-sm text-zinc-500 mt-2">{ticker.y} · {ticker.g.slice(0, 2).join(', ')}</p>
            </div>
          </article>
        )}

        {/* Picked movie card */}
        {picked && !rolling && (
          <article key={picked.t + picked.y} className="mt-6 rounded-3xl bg-gradient-to-br from-zinc-900 to-zinc-900/40 border border-zinc-800 overflow-hidden reveal-card">
            <div className="p-6 sm:p-8">
              <div className="flex items-start justify-between gap-3 mb-1">
                <span className="text-xs uppercase tracking-widest text-amber-400/80 font-medium">Dein Film für heute</span>
                <Sparkles className="w-4 h-4 text-amber-400 shrink-0" />
              </div>
              <h2 className="text-3xl sm:text-4xl font-bold leading-tight tracking-tight mt-2" style={{ fontFamily: 'Georgia, "Times New Roman", serif' }}>
                {picked.t}
              </h2>
              {picked.o && (
                <p className="text-base text-zinc-400 mt-1 italic">{picked.o}</p>
              )}

              {/* Meta row */}
              <div className="flex flex-wrap items-center gap-2 mt-4">
                {picked.y && (
                  <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-zinc-800/60 text-zinc-300 text-sm">
                    <Calendar className="w-3.5 h-3.5" /> {picked.y}
                  </span>
                )}
                {picked.r && (
                  <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-zinc-800/60 text-zinc-300 text-sm">
                    <Clock className="w-3.5 h-3.5" /> {formatRuntime(picked.r)}
                  </span>
                )}
                {picked.s !== null && picked.s !== undefined && (
                  <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-amber-500/10 text-amber-300 border border-amber-500/20 text-sm font-medium">
                    <Star className="w-3.5 h-3.5 fill-amber-400 text-amber-400" /> {picked.s.toFixed(1).replace('.', ',')}
                  </span>
                )}
                {picked.f !== null && picked.f !== undefined && (
                  <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg border text-sm font-medium ${fskColor(picked.f)}`}>
                    FSK {picked.f}
                  </span>
                )}
              </div>

              {/* Genres */}
              <div className="flex flex-wrap gap-1.5 mt-3">
                {picked.g.map(g => (
                  <span key={g} className="px-2 py-0.5 rounded-md bg-zinc-800/40 text-zinc-400 text-xs">{g}</span>
                ))}
              </div>

              {/* External links (always available once picked) */}
              <div className="mt-6 pt-5 border-t border-zinc-800/60">
                <div className="grid grid-cols-3 gap-2">
                  <button
                    onClick={() => {
                      const q = encodeURIComponent((picked.o || picked.t) + ' ' + (picked.y || '') + ' trailer');
                      const appUrl = `youtube://results?search_query=${q}`;
                      const webUrl = `https://www.youtube.com/results?search_query=${q}+deutsch`;
                      // Try opening YouTube app; if it doesn't grab focus within 800ms, fall back to web
                      let fallbackTimer = setTimeout(() => {
                        window.open(webUrl, '_blank', 'noopener');
                      }, 800);
                      const cancel = () => { if (document.hidden) clearTimeout(fallbackTimer); };
                      document.addEventListener('visibilitychange', cancel, { once: true });
                      window.location.href = appUrl;
                    }}
                    className="py-3 rounded-xl bg-rose-500/15 border border-rose-500/30 text-rose-200 text-sm font-medium flex items-center justify-center gap-1.5 active:scale-[0.98] transition-transform"
                  >
                    <Youtube className="w-4 h-4" /> Trailer
                  </button>
                  <a
                    href={`https://www.imdb.com/find/?q=${encodeURIComponent((picked.o || picked.t))}&s=tt&ttype=ft`}
                    target="_blank" rel="noopener noreferrer"
                    className="py-3 rounded-xl bg-amber-500/15 border border-amber-500/30 text-amber-200 text-sm font-medium flex items-center justify-center gap-1.5 active:scale-[0.98] transition-transform"
                  >
                    <ExternalLink className="w-4 h-4" /> IMDb
                  </a>
                  <a
                    href={`https://www.filmstarts.de/suche/?q=${encodeURIComponent(picked.t)}`}
                    target="_blank" rel="noopener noreferrer"
                    className="py-3 rounded-xl bg-emerald-500/15 border border-emerald-500/30 text-emerald-200 text-sm font-medium flex items-center justify-center gap-1.5 active:scale-[0.98] transition-transform"
                  >
                    <Globe className="w-4 h-4" /> Filmstarts
                  </a>
                </div>
              </div>
            </div>
          </article>
        )}

        {!picked && !rolling && (
          <div className="mt-8 text-center py-12">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-3xl bg-zinc-900 border border-zinc-800 mb-4">
              <Dices className="w-9 h-9 text-zinc-700" strokeWidth={1.5} />
            </div>
            <p className="text-zinc-300 text-sm">Drück den Button und lass dich überraschen</p>
          </div>
        )}

        <footer className="mt-12 pt-6 border-t border-zinc-900 text-center">
          <p className="text-xs text-zinc-500">Filmwürfel · TAM-spy Mediathek · {MOVIES.length.toLocaleString('de-DE')} Filme</p>
        </footer>
        </div>
      </div>
    </>
  );
}
